// Build the LLM prompt from the persona definition + the data we just
// queried. The persona's SYSTEM.md content is embedded here intentionally:
// the workflow IS the runtime, so the prompt lives where the runtime lives.
// If the persona SYSTEM.md changes, this workflow should be regenerated
// from the persona file (TBD: a deploy-persona-to-workflow helper).

const data = $json.data || {};
const staleness = data.sync_freshness_minutes || 0;

// Skip path: sync is stuck
if (staleness > 120) {
  return [{
    json: {
      skip: true,
      reason: 'sync_stale',
      text: `:warning: Slack sync hasn't run in ${Math.round(staleness)} minutes. Today's digest is skipped. Check n8n executions for the slack-mirror-sync workflow.`,
      staleness_minutes: staleness
    }
  }];
}

// Skip path: nothing happened
if ((data.message_count_24h || 0) === 0) {
  return [{
    json: {
      skip: true,
      reason: 'quiet_day',
      text: `:sunrise: Slack digest — ${new Date().toLocaleDateString('en-US', {weekday: 'long', month: 'long', day: 'numeric'})}\n\nQuiet day yesterday. No messages in any monitored channel.`
    }
  }];
}

const systemPrompt = `You are the communications agent for a small team that uses Slack. You read the Slack workspace (via a read-only postgres mirror, updated hourly) and post insights to Mattermost. Your goal is to make the operator feel they have a high-leverage view of their Slack without reading every channel.

Tone: plain prose, short sentences, concrete. Name channels, name themes, paraphrase faithfully. No filler phrases like 'continues to demonstrate' or 'as we move forward'. No editorializing about individuals.

Produce a morning digest with this structure:
\`\`\`
:sunrise: **Slack digest — <weekday, date>**

**Yesterday across <N> channels:** <one sentence about volume + themes>

**Worth your attention:**
- <thread or item 1: 1-2 sentences explaining why>
- <thread or item 2>
- <thread or item 3>

**Dangling:** <questions without replies, if any — optional section>

**Quiet:** <users who used to post regularly, didn't this week — optional section, only if pattern is meaningful>
\`\`\`

Reading time target: 60-90 seconds. If the data is thin, the digest is short. Don't pad. Sections are optional. Drop a section if it has nothing in it.

Do NOT include verbatim quotes longer than 30 words. Paraphrase. Do NOT name individuals as 'unproductive' or 'noisy'. Activity patterns can be reported neutrally.`;

const dateStr = new Date().toLocaleDateString('en-US', {weekday: 'long', month: 'long', day: 'numeric'});

const userPrompt = `Compose today's morning Slack digest for ${dateStr}.

Here is the data from the postgres mirror:

**Volume:** ${data.message_count_24h} messages across ${data.active_channel_count_24h} active channels in the last 24 hours.

**Channel activity (top channels yesterday):**
${JSON.stringify(data.channel_activity, null, 2)}

**Unanswered questions in threads (age between 6 and 48 hours):**
${JSON.stringify(data.unanswered_questions, null, 2)}

**Messages indicating decisions being discussed (last 24h):**
${JSON.stringify(data.decisions, null, 2)}

**Action items assigned to people (last 24h):**
${JSON.stringify(data.action_items, null, 2)}

**Messages with high reaction counts (>3, last 24h):**
${JSON.stringify(data.high_reaction_messages, null, 2)}

**Users quieter than usual this week:**
${JSON.stringify(data.quiet_users, null, 2)}

Now produce the digest. Reading time 60-90 sec. If nothing in a section is signal, drop the section. Lead with what's worth their attention.`;

return [{
  json: {
    skip: false,
    system_prompt: systemPrompt,
    user_prompt: userPrompt,
    raw_data: data
  }
}];

// Extract the LLM text. Ollama returns: { message: { role, content }, ... }
const content = ($json.message && $json.message.content) || '';
if (!content || content.length < 50) {
  return [{ json: { skip: true, reason: 'llm_short_output', text: `:warning: comms-agent produced a suspiciously short digest (${content.length} chars). Check Ollama model + prompt.` } }];
}
return [{ json: { skip: false, text: content.trim(), llm_chars: content.length } }];
